from docx import Document
d = Document('/workspace/output/governance-diligence-memo.docx')
print('=== TABLES ===')
for i,t in enumerate(d.tables):
    print(f'Table {i+1}: {len(t.rows)} rows x {len(t.columns)} cols')
    print('  Header:', ' | '.join(c.text[:22] for c in t.rows[0].cells))
print()
print('=== ALL HEADING 1 / HEADING 2 (structure) ===')
for p in d.paragraphs:
    if p.style.name in ('Heading 1','Heading 2'):
        print(f'  [{p.style.name}] {p.text}')
" 2>&1"}

